JS_CODE = 'const QUESTIONS = [\n  {id:\'bill\', q:\'Q1. 現在の月々の電気代はおよそいくらですか？\', opts:[\'3,000円未満\',\'3,000〜6,000円\',\'6,000〜10,000円\',\'10,000〜15,000円\',\'15,000〜20,000円\',\'20,000円以上\']},\n  {id:\'family\', q:\'Q2. 家族構成は？\', opts:[\'一人暮らし\',\'2人（夫婦・カップル）\',\'3〜4人家族\',\'5人以上の大家族\']},\n  {id:\'dwelling\', q:\'Q3. 住居タイプは？\', opts:[\'マンション・アパート（賃貸）\',\'マンション（分譲）\',\'一戸建て（賃貸）\',\'一戸建て（持ち家）\']},\n  {id:\'peakTime\', q:\'Q4. 主に電気を使う時間帯は？\', opts:[\'朝（6〜9時）と夜（18〜23時）が多い\',\'日中（9〜18時）が多い（在宅ワーク等）\',\'夜間（22時〜翌6時）が多い（夜型）\',\'一日中まんべんなく使う\']},\n  {id:\'allElectric\', q:\'Q5. オール電化住宅ですか？\', opts:[\'はい（給湯・調理すべて電気）\',\'いいえ（ガスも使っている）\',\'わからない\']},\n  {id:\'solar\', q:\'Q6. 太陽光発電を導入していますか？\', opts:[\'していない\',\'している（売電中）\',\'導入を検討中\']},\n  {id:\'gasElec\', q:\'Q7. ガスと電気をセット契約したいですか？\', opts:[\'はい（ガス電気セット割引を狙いたい）\',\'いいえ（電気だけ変えたい）\',\'どちらでもよい\']},\n  {id:\'priority\', q:\'Q8. 電力会社・プラン選びで最も重視するのは？\', opts:[\'とにかく安さ（コスト削減）\',\'環境（再生可能エネルギー）\',\'サービス・ポイント還元\',\'手続きの簡単さ\',\'大手の安心感\']},\n];\n\nlet answers = {}, currentQ = 0;\n\nfunction renderQ() {\n  const q = QUESTIONS[currentQ];\n  document.getElementById(\'qNum\').textContent = currentQ + 1;\n  const pct = Math.round(((currentQ + 1) / QUESTIONS.length) * 100);\n  document.getElementById(\'qPct\').textContent = pct;\n  document.getElementById(\'progressBar\').style.width = pct + \'%\';\n  document.getElementById(\'backBtn\').classList.toggle(\'hidden\', currentQ === 0);\n  document.getElementById(\'questionContainer\').innerHTML = `\n    <h2 class="text-lg font-bold text-gray-800 mb-4">${q.q}</h2>\n    <div class="space-y-2">\n      ${q.opts.map((opt, i) => `\n        <button onclick="selectOpt(${i})"\n          class="w-full text-left px-4 py-3 rounded-xl border-2 text-sm font-medium transition-all\n          ${answers[q.id] === i ? \'border-orange-500 bg-orange-50 text-orange-700\' : \'border-gray-200 bg-gray-50 hover:border-orange-300 text-gray-700\'}">\n          ${opt}\n        </button>`).join(\'\')}\n    </div>`;\n}\n\nfunction selectOpt(i) { answers[QUESTIONS[currentQ].id] = i; renderQ(); }\nfunction prevQ() { if (currentQ > 0) { currentQ--; renderQ(); } }\nfunction nextQ() {\n  if (answers[QUESTIONS[currentQ].id] === undefined) { alert(\'選択してください\'); return; }\n  if (currentQ < QUESTIONS.length - 1) { currentQ++; renderQ(); }\n  else showResult();\n}\n\nfunction showResult() {\n  document.getElementById(\'quizArea\').classList.add(\'hidden\');\n  document.getElementById(\'resultArea\').classList.remove(\'hidden\');\n\n  const bill = answers.bill; // 0-5\n  const peakTime = answers.peakTime; // 0-3\n  const allElec = answers.allElectric; // 0-2\n  const solar = answers.solar; // 0-2\n  const priority = answers.priority; // 0-4\n\n  let planType, planDesc, emoji, savingPct;\n\n  if (allElec === 0 || peakTime === 2) {\n    // オール電化 or 夜型\n    planType = \'🌙 夜間割引型プラン（時間帯別料金）\';\n    planDesc = \'深夜電力が安くなるプランが最適です。電気給湯器・食洗機・洗濯乾燥機を夜間に回すことで大幅節約が可能。「スマートライフプラン」「深夜電力B」などが相当します。\';\n    emoji = \'🌙\';\n    savingPct = 0.18;\n  } else if (priority === 1 || solar === 1) {\n    // 環境重視 or 太陽光あり\n    planType = \'🌱 再生可能エネルギー型プラン\';\n    planDesc = \'環境への配慮と電気代削減を両立。太陽光発電との組み合わせで売電収入も最大化できます。「再エネ100%」「グリーン電力」などのプランを検討しましょう。\';\n    emoji = \'🌱\';\n    savingPct = 0.08;\n  } else if (peakTime === 1) {\n    // 日中在宅\n    planType = \'☀️ 日中割引型プラン（太陽光連動）\';\n    planDesc = \'日中の在宅ワークが多い場合は、昼間の電気代が安いプランが有利です。太陽光発電を導入している場合はさらに有利になります。\';\n    emoji = \'☀️\';\n    savingPct = 0.12;\n  } else {\n    // 一般的\n    planType = \'📊 フラット型プラン（新電力）\';\n    planDesc = \'時間帯に関わらず一定料金のシンプルなプランが最適。新電力会社（Looopでんき・東京ガス電力など）への乗り換えで基本料金の削減が見込めます。\';\n    emoji = \'📊\';\n    savingPct = 0.10;\n  }\n\n  document.getElementById(\'rEmoji\').textContent = emoji;\n  document.getElementById(\'planType\').textContent = planType;\n  document.getElementById(\'planDesc\').textContent = planDesc;\n\n  const billAmounts = [2000, 4500, 8000, 12500, 17500, 25000];\n  const monthlyBill = billAmounts[bill];\n  const yearlyBill = monthlyBill * 12;\n  const saving = Math.round(yearlyBill * savingPct / 1000) * 1000;\n\n  document.getElementById(\'rBadge\').textContent = \'年間約\' + saving.toLocaleString() + \'円節約見込み\';\n  document.getElementById(\'rBadge\').className = \'inline-block px-4 py-1 rounded-full t'
